import pymongo
from pymongo import MongoClient
from typing import Dict, List, Any, Optional
import json
import re


class MongoDBAdvancedFilter:
    def __init__(self, connection_string: str = "mongodb://localhost:27017/", database_name: str = "advanced_filter_db"):
        self.client = MongoClient(connection_string)
        self.db = self.client[database_name]
        
    def create_sample_data(self, collection_name: str = "products"):
        collection = self.db[collection_name]
        collection.delete_many({})
        
        sample_data = [
            {"name": "Laptop", "price": 1200, "category": "Electronics", "stock": 15, "rating": 4.5},
            {"name": "Mouse", "price": 25, "category": "Electronics", "stock": 100, "rating": 4.2},
            {"name": "Keyboard", "price": 75, "category": "Electronics", "stock": 50, "rating": 4.7},
            {"name": "Monitor", "price": 300, "category": "Electronics", "stock": 30, "rating": 4.4},
            {"name": "Desk", "price": 250, "category": "Furniture", "stock": 20, "rating": 4.0},
            {"name": "Chair", "price": 150, "category": "Furniture", "stock": 35, "rating": 4.3},
            {"name": "Lamp", "price": 40, "category": "Furniture", "stock": 60, "rating": 3.9},
            {"name": "Notebook", "price": 5, "category": "Stationery", "stock": 200, "rating": 4.1},
            {"name": "Pen", "price": 2, "category": "Stationery", "stock": 500, "rating": 4.0},
            {"name": "Headphones", "price": 80, "category": "Electronics", "stock": 45, "rating": 4.6}
        ]
        
        collection.insert_many(sample_data)
        print(f"Inserted {len(sample_data)} sample documents into '{collection_name}' collection")
        
    def execute_where_query(self, collection_name: str, js_expression: str, projection: Optional[Dict] = None) -> List[Dict]:
        collection = self.db[collection_name]
        
        query = {"$where": js_expression}
        
        if projection:
            results = collection.find(query, projection)
        else:
            results = collection.find(query)
            
        return list(results)
    
    def filter_by_custom_logic(self, collection_name: str, js_function: str) -> List[Dict]:
        collection = self.db[collection_name]
        
        query = {"$where": js_function}
        results = collection.find(query)
        
        return list(results)
    
    def complex_price_filter(self, collection_name: str, min_price: float, max_price: float, stock_threshold: int) -> List[Dict]:
        js_expression = f"this.price >= {min_price} && this.price <= {max_price} && this.stock > {stock_threshold}"
        return self.execute_where_query(collection_name, js_expression)
    
    def filter_by_name_length(self, collection_name: str, min_length: int, max_length: int) -> List[Dict]:
        js_expression = f"this.name.length >= {min_length} && this.name.length <= {max_length}"
        return self.execute_where_query(collection_name, js_expression)
    
    def filter_by_calculated_value(self, collection_name: str, calculation: str, threshold: float) -> List[Dict]:
        js_expression = f"({calculation}) > {threshold}"
        return self.execute_where_query(collection_name, js_expression)
    
    def filter_with_regex_logic(self, collection_name: str, field: str, pattern: str) -> List[Dict]:
        js_expression = f"/{pattern}/.test(this.{field})"
        return self.execute_where_query(collection_name, js_expression)
    
    def advanced_multi_condition_filter(self, collection_name: str, conditions: List[str], operator: str = "&&") -> List[Dict]:
        js_expression = f" {operator} ".join([f"({cond})" for cond in conditions])
        return self.execute_where_query(collection_name, js_expression)
    
    def filter_by_user_expression(self, collection_name: str, user_expression: str) -> List[Dict]:
        return self.execute_where_query(collection_name, user_expression)
    
    def aggregate_with_where(self, collection_name: str, js_expression: str, group_by: str = None) -> List[Dict]:
        collection = self.db[collection_name]
        
        pipeline = [
            {"$match": {"$where": js_expression}}
        ]
        
        if group_by:
            pipeline.append({
                "$group": {
                    "_id": f"${group_by}",
                    "count": {"$sum": 1},
                    "avg_price": {"$avg": "$price"},
                    "total_stock": {"$sum": "$stock"}
                }
            })
        
        results = collection.aggregate(pipeline)
        return list(results)
    
    def filter_with_function_call(self, collection_name: str, function_body: str) -> List[Dict]:
        js_function = f"function() {{ {function_body} }}"
        return self.execute_where_query(collection_name, js_function)
    
    def complex_inventory_filter(self, collection_name: str) -> List[Dict]:
        js_expression = "this.price * this.stock > 1000 && this.rating >= 4.0"
        return self.execute_where_query(collection_name, js_expression)
    
    def filter_by_price_per_rating(self, collection_name: str, max_ratio: float) -> List[Dict]:
        js_expression = f"this.price / this.rating < {max_ratio}"
        return self.execute_where_query(collection_name, js_expression)
    
    def custom_scoring_filter(self, collection_name: str, min_score: float) -> List[Dict]:
        js_expression = f"(this.rating * 10 + this.stock / 10) > {min_score}"
        return self.execute_where_query(collection_name, js_expression)
    
    def filter_with_string_operations(self, collection_name: str, category_prefix: str, name_contains: str) -> List[Dict]:
        js_expression = f"this.category.startsWith('{category_prefix}') && this.name.toLowerCase().includes('{name_contains.lower()}')"
        return self.execute_where_query(collection_name, js_expression)
    
    def dynamic_threshold_filter(self, collection_name: str, field1: str, field2: str, multiplier: float) -> List[Dict]:
        js_expression = f"this.{field1} > this.{field2} * {multiplier}"
        return self.execute_where_query(collection_name, js_expression)
    
    def close(self):
        self.client.close()


def print_results(results: List[Dict], title: str = "Query Results"):
    print(f"\n{'='*60}")
    print(f"{title}")
    print(f"{'='*60}")
    
    if not results:
        print("No results found")
        return
    
    for idx, doc in enumerate(results, 1):
        doc_copy = doc.copy()
        if '_id' in doc_copy:
            doc_copy['_id'] = str(doc_copy['_id'])
        print(f"{idx}. {json.dumps(doc_copy, indent=2)}")
    
    print(f"\nTotal results: {len(results)}")


